sql:
SELECT tradition_id, AVG(percentage) AS average_percentage
FROM tradition_income_data
GROUP BY tradition_id;

SELECT level_name
FROM income_levels
WHERE min_income > 100000;

SELECT value 
FROM tradition_demographic_data 
WHERE tradition_id = 0 AND factor_id = 0;

SELECT tradition_name, number_of_followers AS total_followers
FROM religious_traditions
WHERE origin_country = 'India';

SELECT AVG(number_of_followers) 
FROM religious_traditions 
WHERE origin_country = 'USA';

SELECT DISTINCT T1.source_name, T1.url
FROM data_sources AS T1
INNER JOIN tradition_income_data AS T2 ON T1.source_id = T2.source_id;

external_knowledge:
- 'big religious groups': religious traditions with more than 1 billion followers;
- 'noticeable share': more than 10% (percentage > 0.1);
- 'under $30k a year': income level 'Less than $30,000';
- 'recent data': data from the year 2023.

sql:
SELECT AVG(value) 
FROM tradition_demographic_data 
WHERE factor_id = 0;

SELECT 
    (SELECT COUNT(*) FROM users WHERE is_active = 1 AND last_login_date >= DATE('now', '-1 year')) AS active_users,
    (SELECT COUNT(*) FROM users WHERE is_active = 1) AS total_users;

SELECT tradition_name 
FROM religious_traditions 
WHERE number_of_followers = (SELECT MAX(number_of_followers) FROM religious_traditions);

SELECT tradition_name, origin_country
FROM religious_traditions
WHERE tradition_id = 1 AND founding_year > 2000;

SELECT version_date
FROM tradition_income_data_versions
WHERE tradition_id = 1 AND level_id = 1;

SELECT tradition_name, number_of_followers 
FROM religious_traditions 
WHERE origin_country = 'USA';
